
-- Fix asset_id unique constraint: allow same asset_id across different tenants
ALTER TABLE public.assets DROP CONSTRAINT assets_asset_id_key;
CREATE UNIQUE INDEX assets_asset_id_tenant_unique ON public.assets (asset_id, tenant_id);

-- Similarly fix risk_id if it has a global unique constraint
-- (risk_id is generated by trigger, should also be per-tenant)

-- Create a function to seed 93 Annex A controls for a tenant
CREATE OR REPLACE FUNCTION public.seed_controls_for_tenant(_tenant_id uuid)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $$
BEGIN
  -- Only seed if tenant has no controls yet
  IF EXISTS (SELECT 1 FROM public.controls WHERE tenant_id = _tenant_id LIMIT 1) THEN
    RETURN;
  END IF;

END;
$$;

-- Update create_tenant_and_assign to also seed controls
CREATE OR REPLACE FUNCTION public.create_tenant_and_assign(_name text, _domain text DEFAULT NULL::text, _industry text DEFAULT ''::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $$
DECLARE
  _tenant_id uuid;
  _user_id uuid := auth.uid();
BEGIN
  VALUES (_name, _domain, _industry)
  RETURNING id INTO _tenant_id;

  VALUES (_user_id, _tenant_id);

  UPDATE public.profiles SET tenant_id = _tenant_id WHERE id = _user_id;

  DELETE FROM public.user_roles WHERE user_id = _user_id;


  -- Seed 93 Annex A controls for the new tenant
  PERFORM public.seed_controls_for_tenant(_tenant_id);

  RETURN _tenant_id;
END;
$$;

-- Update generate_risk_id to be per-tenant
CREATE OR REPLACE FUNCTION public.generate_risk_id()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $$
DECLARE
  next_num integer;
BEGIN
  SELECT COALESCE(MAX(
    CASE WHEN risk_id ~ '^RISK-\d+$' 
    THEN CAST(SUBSTRING(risk_id FROM 6) AS integer) 
    ELSE 0 END
  ), 0) + 1 INTO next_num FROM public.risks WHERE tenant_id = NEW.tenant_id;
  NEW.risk_id := 'RISK-' || next_num;
  RETURN NEW;
END;
$$;

-- Allow all authenticated users to delete controls (not just admins)
DROP POLICY IF EXISTS "Admin manage controls" ON public.controls;
CREATE POLICY "Tenant manage controls" ON public.controls
  FOR ALL TO authenticated
  USING (tenant_id = get_user_tenant_id())
  WITH CHECK (tenant_id = get_user_tenant_id());
